import { useState } from 'react';import { useMutation,useQueryClient } from '@tanstack/react-query';import { Alert } from '@/components/ui/alert';import { Button } from '@/components/ui/button';import { usePermissions } from '@/hooks/usePermissions';import { apiErrorMessage } from '@/lib/apiClient';import { vendorApi } from '../api/vendorApi';import { useSaveContract,useSuppliers,useVendorContracts } from '../api/useVendors';import { ContractForm } from '../components/ContractForm';import { ContractTimeline } from '../components/ContractTimeline';import { VendorModal } from '../components/VendorModal';import type { ContractFormValues,SupplierContract } from '../types';
export const ContractsPage=()=>{const [filters,setFilters]=useState({search:'',status:'',expiring_before:''});const [editing,setEditing]=useState<SupplierContract|null|undefined>();const [vendorId,setVendorId]=useState(0);const {can}=usePermissions();const client=useQueryClient();const list=useVendorContracts({...filters,per_page:100});const suppliers=useSuppliers({status:'active',per_page:100});const target=editing?.vendor_id??vendorId;const save=useSaveContract(target,editing?.id);const remove=useMutation({mutationFn:(c:SupplierContract)=>vendorApi.deleteContract(c.vendor_id,c.id),onSuccess:()=>void client.invalidateQueries({queryKey:['vendors']})});const submit=async(v:ContractFormValues)=>{await save.mutateAsync(v);setEditing(undefined);};const contracts=list.data?.data.map(x=>x.attributes)??[];const expiring=()=>setFilters(f=>({...f,status:'active',expiring_before:new Date(Date.now()+30*86400000).toISOString().slice(0,10)}));return <div className="space-y-5 text-slate-800 dark:text-slate-100"><header className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs font-bold uppercase tracking-[.18em] text-indigo-600">Vendor Management</p><h1 className="mt-2 text-2xl font-bold">Supplier Contracts</h1><p className="mt-1 text-sm text-slate-500">Contract values, renewals, expiry, and attachment placeholders.</p></div><Button variant="secondary" onClick={expiring}>Expiring in 30 Days</Button></header><div className="flex flex-wrap gap-3 rounded-xl border bg-white p-4 dark:border-slate-700 dark:bg-slate-900"><input placeholder="Contract or supplier…" value={filters.search} onChange={e=>setFilters({...filters,search:e.target.value})} className="h-10 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800"/><select value={filters.status} onChange={e=>setFilters({...filters,status:e.target.value,expiring_before:''})} className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800"><option value="">All statuses</option>{['draft','active','expired','terminated','renewed'].map(x=><option key={x}>{x}</option>)}</select>{can('vendors.contracts')?<div className="ml-auto flex gap-2"><select value={vendorId} onChange={e=>setVendorId(Number(e.target.value))} className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800"><option value={0}>Select supplier</option>{suppliers.data?.data.map(x=><option key={x.attributes.id} value={x.attributes.id}>{x.attributes.company_name}</option>)}</select><Button disabled={!vendorId} onClick={()=>setEditing(null)}>Add Contract</Button></div>:null}</div>{list.error||remove.error?<Alert variant="danger" title="Contract operation failed">{apiErrorMessage(list.error||remove.error)}</Alert>:null}<section className="rounded-xl border bg-slate-50 p-6 dark:border-slate-700 dark:bg-slate-950"><ContractTimeline contracts={contracts} onEdit={can('vendors.contracts')?c=>{setVendorId(c.vendor_id);setEditing(c);}:undefined} onDelete={can('vendors.contracts')?c=>{if(confirm(`Terminate ${c.contract_number}?`))remove.mutate(c);}:undefined}/></section>{editing!==undefined&&target>0?<VendorModal title={editing?'Edit Contract':'Add Contract'} onClose={()=>setEditing(undefined)}><ContractForm contract={editing} currency={suppliers.data?.data.find(x=>x.attributes.id===target)?.attributes.currency} onSubmit={v=>void submit(v)} onCancel={()=>setEditing(undefined)} isLoading={save.isPending}/></VendorModal>:null}</div>;};
